module pulse_detect #(
    parameter s0 = 2'b00,
    parameter s1 = 2'b01,
    parameter s2 = 2'b10,
    parameter s3 = 2'b11
) (
    input clk,
    input rst_n,
    input data_in,
    output reg data_out
);
    reg [1:0] state;

    always @(posedge clk or negedge rst_n) begin
        if (~rst_n) begin
            state <= s0;
            data_out <= 1'b0;
        end
        else begin
            case (state)
                s0: begin
                    if (data_in) begin
                        state <= s1;
                    end
                    else begin
                        state <= s0;
                    end
                    data_out <= 1'b0;
                end
                s1: begin
                    if (data_in) begin
                        state <= s2;
                    end
                    else begin
                        state <= s0;
                    end
                    data_out <= 1'b0;
                end
                s2: begin
                    if (~data_in) begin
                        state <= s3;
                    end
                    else begin
                        state <= s2;
                    end
                    data_out <= 1'b0;
                end
                s3: begin
                    if (data_in) begin
                        state <= s1;
                    end
                    else begin
                        state <= s0;
                    end
                    data_out <= 1'b1;
                end
                default: begin
                    state <= s0;
                    data_out <= 1'b0;
                end
            endcase
        end
    end
endmodule
